#include <stdio.h>

void selectionSort(int arr[], int n) {
    for (int i = 0; i < n - 1; i++) {
        int min_idx = i;
        for (int j = i + 1; j < n; j++) {
            if (arr[j] < arr[min_idx]) min_idx = j;
        }
        int temp = arr[min_idx];
        arr[min_idx] = arr[i];
        arr[i] = temp;
    }
}

int main() {
    int a[] = {29, 10, 14, 37, 13};
    selectionSort(a, 5);
    for(int i=0; i<5; i++) printf("%d ", a[i]);
    printf("\n");
    return 0;
}

